var getSumAbsoluteDifferences = function(nums) {
    const n = nums.length;
    const total = nums.reduce((a, b) => a + b, 0);
    let prefix = 0;
    const res = [];
    for (let i = 0; i < n; i++) {
        const x = nums[i];
        const left = x * i - prefix;
        const right = (total - prefix - x) - x * (n - i - 1);
        res.push(left + right);
        prefix += x;
    }
    return res;
};
